#include<cmath>
#include<iostream>
#include<algorithm>
using namespace std;

int p[100], a[100], k = 0, s[10005];

void f(int n)
{
	for(int i = 2; i * i <= n; i++)
	{
		if(n % i != 0) continue;
		k++;
		p[k] = i;
		a[k] = 0;
		while(n % i == 0)
		{
			n /= i;
			a[k]++;
		}
	}
	if(n > 1)
	{
		k++;
		p[k] = n;
		a[k] = 1;
	}
}

int min_Time(int s)
{
	int t = 0;
	for(int i = 1; i <= k; i++)
	{
		if(s % p[i] != 0) return 1e9;
		int b = 0;
		while(s % p[i] == 0)
		{
			s /= p[i];
			b++;
		}
		t = max(t, int(ceil(1.0 * a[i] / b)));
	}
	return t;
}

int main(){
	int n, m1, m2, ans = 2e9;
	cin >> n >> m1 >> m2;
	for(int i = 1; i <= n; i++)
		cin >> s[i];
	f(m1);
	for(int i = 1; i <= k; i++)
		a[i] *= m2;
	for(int i = 1; i <= n; i++)
		ans = min(ans, min_Time(s[i]));
	if(ans >= 1e9) cout << -1;
	else cout << ans;
	return 0;
}
